import { describe, expect, it } from 'vitest';

import {
  adist,
  admitBearing,
  broadsideBearing,
  consistent,
  countConsistent,
  DirectionOfArrivalMaster,
  nodeA,
  nodeB,
  nodeC,
  predictedArrival,
  realNodes,
  residual,
  spoofNode,
  trueBearing,
  type MeshNode,
} from '../src/direction-of-arrival';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(118, 100)).toBe(18);
    expect(adist(100, 118)).toBe(18);
    expect(adist(0, 20)).toBe(20);
  });

  it('saturates at zero (Nat truncated subtraction)', () => {
    expect(adist(0, 0)).toBe(0);
    expect(Math.max(0, 4 - 9)).toBe(0);
  });
});

describe('predictedArrival (mirrors predicted_at_zero / fixture_bearings_distinct)', () => {
  it('at position 0 the predicted arrival is the reference arrival', () => {
    expect(predictedArrival(trueBearing, 0)).toBe(trueBearing.refArrival);
    expect(predictedArrival(broadsideBearing, 0)).toBe(100);
  });

  it('adds slowness * position to the reference arrival (100/106/112)', () => {
    expect(predictedArrival(trueBearing, 0)).toBe(100);
    expect(predictedArrival(trueBearing, 2)).toBe(106);
    expect(predictedArrival(trueBearing, 4)).toBe(112);
  });

  it('a flat broadside bearing predicts the same arrival everywhere', () => {
    expect(predictedArrival(broadsideBearing, 2)).toBe(100);
    expect(predictedArrival(broadsideBearing, 4)).toBe(100);
  });

  it('distinct slownesses give distinct arrivals off the array axis (106 != 100)', () => {
    expect(predictedArrival(trueBearing, 2)).not.toBe(
      predictedArrival(broadsideBearing, 2),
    );
  });

  it('residual is the gap between report and predicted arrival', () => {
    expect(residual(trueBearing, nodeA)).toBe(0);
    expect(residual(trueBearing, nodeB)).toBe(0);
    expect(residual(trueBearing, nodeC)).toBe(0);
    // spoof reports 100 but the true bearing predicts 118 at position 6
    expect(residual(trueBearing, spoofNode)).toBe(18);
  });
});

describe('consistency and counting (mirrors consistentB / countConsistent)', () => {
  it('an honest in-tolerance detecting microphone is consistent', () => {
    expect(consistent(1, trueBearing, nodeA)).toBe(true);
    expect(consistent(1, trueBearing, nodeB)).toBe(true);
    expect(consistent(1, trueBearing, nodeC)).toBe(true);
  });

  it('an undetected microphone is never consistent even at exact arrival', () => {
    const silent: MeshNode = { ...nodeA, detected: false };
    expect(consistent(1, trueBearing, silent)).toBe(false);
  });

  it('counts the mutually-consistent microphones for the true bearing', () => {
    expect(countConsistent(1, trueBearing, realNodes)).toBe(3);
    expect(countConsistent(1, trueBearing, [nodeA])).toBe(1);
    expect(countConsistent(1, trueBearing, [spoofNode])).toBe(0);
  });

  it('the broadside bearing is consistent with only the position-0 microphone', () => {
    expect(countConsistent(1, broadsideBearing, realNodes)).toBe(1);
    expect(consistent(1, broadsideBearing, nodeA)).toBe(true);
    expect(consistent(1, broadsideBearing, nodeB)).toBe(false);
  });
});

describe('promotion check: admitBearing', () => {
  it('admits when a quorum K>=2 of microphones agree on the moveout', () => {
    // mirrors true_bearing_admitted (K=2) and true_bearing_full_quorum (K=3)
    const two = admitBearing(realNodes, trueBearing, 2, 1);
    expect(two.outcome).toBe('claim_admitted');
    expect(two.quorumMet).toBe(true);
    expect(two.consistentCount).toBe(3);
    expect(two.consistentNodes).toEqual([0, 1, 2]);

    const three = admitBearing(realNodes, trueBearing, 3, 1);
    expect(three.outcome).toBe('claim_admitted');
    expect(three.quorumMet).toBe(true);
  });

  it('downgrades to observation_only when consistent microphones are below quorum', () => {
    // the broadside bearing reaches only one microphone: below the quorum of two.
    // mirrors wrong_bearing_not_admitted
    const a = admitBearing(realNodes, broadsideBearing, 2, 1);
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.consistentCount).toBe(1);
    expect(a.consistentNodes).toEqual([0]);
  });

  it('refuses to admit at K<2 even when microphones are consistent (one arrival fits every bearing)', () => {
    // mirrors single_node_no_bearing: a lone arrival resolves no direction.
    const a = admitBearing(realNodes, trueBearing, 1, 1);
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.summary).toContain('< 2');
  });

  it('downgrades a single consistent microphone to observation_only at quorum two', () => {
    // mirrors lone_node_not_admitted
    const a = admitBearing([nodeA], trueBearing, 2, 1);
    expect(a.outcome).toBe('observation_only');
    expect(a.quorumMet).toBe(false);
    expect(a.consistentCount).toBe(1);
    expect(a.consistentNodes).toEqual([0]);
  });

  it('withholds when no microphone is consistent with the bearing', () => {
    const a = admitBearing([spoofNode], trueBearing, 2, 1);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.quorumMet).toBe(false);
    expect(a.consistentCount).toBe(0);
    expect(a.consistentNodes).toEqual([]);
  });
});

describe('spoof rejection + non-inflation (mirrors spoof_node_inconsistent / spoof_does_not_inflate)', () => {
  it('the spoof microphone is inconsistent with the confirmed bearing', () => {
    expect(consistent(1, trueBearing, spoofNode)).toBe(false);
  });

  it('the spoof cannot inflate the consistency count', () => {
    expect(countConsistent(1, trueBearing, [...realNodes, spoofNode])).toBe(
      countConsistent(1, trueBearing, realNodes),
    );
  });

  it('the spoof does not appear among the admitted microphones', () => {
    const a = admitBearing([...realNodes, spoofNode], trueBearing, 2, 1);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.consistentCount).toBe(3);
    // index 3 (the spoof) is excluded
    expect(a.consistentNodes).toEqual([0, 1, 2]);
  });
});

describe('hard negative: same reference arrival, opposite verdicts', () => {
  it('the true and broadside bearings share refArrival but split on admission', () => {
    // mirrors same_ref_opposite_verdict
    expect(trueBearing.refArrival).toBe(broadsideBearing.refArrival);
    expect(admitBearing(realNodes, trueBearing, 2, 1).outcome).toBe(
      'claim_admitted',
    );
    expect(admitBearing(realNodes, broadsideBearing, 2, 1).outcome).not.toBe(
      'claim_admitted',
    );
  });
});

describe('DirectionOfArrivalMaster (mirrors doa_master)', () => {
  it('every boundary witness holds', () => {
    expect(DirectionOfArrivalMaster.trueBearingAdmittedAtTwo).toBe(true);
    expect(DirectionOfArrivalMaster.trueBearingAdmittedAtThree).toBe(true);
    expect(DirectionOfArrivalMaster.broadsideNotAdmitted).toBe(true);
    expect(DirectionOfArrivalMaster.loneNodeNotAdmitted).toBe(true);
    expect(DirectionOfArrivalMaster.bearingsDistinctOfSlowness).toBe(true);
    expect(DirectionOfArrivalMaster.spoofNodeInconsistent).toBe(true);
    expect(DirectionOfArrivalMaster.spoofDoesNotInflate).toBe(true);
    expect(DirectionOfArrivalMaster.sameRefOppositeVerdict).toBe(true);
  });
});
